approaches.sql:
SELECT
  (SELECT COUNT(*) FROM (SELECT user FROM web_logins UNION ALL SELECT user FROM app_logins)) AS all_count,
  (SELECT COUNT(*) FROM (SELECT user FROM web_logins UNION     SELECT user FROM app_logins)) AS distinct_count;

